/**
 * Signals in message Log_States.
 *
 * all of the states of the car
 *
 * All signal values are as on the CAN bus.
 */
struct sensor_log_states_t {
    /**
     * if the pump is enabled
     *
     * Range: 0..1 (0..1 flag)
     * Scale: 1
     * Offset: 0
     */
    uint8_t pump_enabled;

    /**
     * if the fans are enabled
     *
     * Range: 0..1 (0..1 flag)
     * Scale: 1
     * Offset: 0
     */
    uint8_t fans_enabled;

    /**
     * if the motors are allowed to regen
     *
     * Range: 0..1 (0..1 flag)
     * Scale: 1
     * Offset: 0
     */
    uint8_t regen_enabled;

    /**
     * if the motors are allowed to do any torque (regen and discharge)
     *
     * Range: 0..1 (0..1 flag)
     * Scale: 1
     * Offset: 0
     */
    uint8_t motors_enabled;

    /**
     * if the car is ready to drive
     *
     * Range: 0..1 (0..1 flag)
     * Scale: 1
     * Offset: 0
     */
    uint8_t rtd;

    /**
     * if the AIRS have been opened
     *
     * Range: 0..1 (0..1 flag)
     * Scale: 1
     * Offset: 0
     */
    uint8_t airs;

    /**
     * if the ECU has opened the AIRS
     *
     * Range: 0..1 (0..1 flag)
     * Scale: 1
     * Offset: 0
     */
    uint8_t ecu_open_airs;

    /**
     * if the speed limit is enabled
     *
     * Range: 0..1 (0..1 flag)
     * Scale: 1
     * Offset: 0
     */
    uint8_t speed_limit_enabled;

    /**
     * just a time value
     *
     * Range: -
     * Scale: 0.01
     * Offset: 0
     */
    uint32_t time;
};

